<?php
namespace App\Http\Controllers;
use App\Models\{LockDevice,LockProviderConfig,LockWebhookEvent,RoomEvent,User};use App\Notifications\LockHealthAlert;use App\Services\Security\AuditLogger;use Illuminate\Http\{JsonResponse,Request};use Illuminate\Support\Facades\Notification;
class LockWebhookController extends Controller{public function handle(Request$request,string$providerKey):JsonResponse{$provider=LockProviderConfig::where('key',$providerKey)->where('active',true)->firstOrFail();$signature=(string)$request->header('X-Lock-Signature');abort_unless(filled($provider->webhook_secret)&&hash_equals(hash_hmac('sha256',$request->getContent(),$provider->webhook_secret),$signature),401,'Invalid webhook signature.');$v=$request->validate(['id'=>['nullable','string','max:255'],'type'=>['required','string','max:100'],'device_id'=>['required','string','max:255'],'status'=>['nullable','string','max:50'],'battery_level'=>['nullable','integer','between:0,100'],'occurred_at'=>['nullable','date']]);if(filled($v['id']??null)&&LockWebhookEvent::where('provider_key',$providerKey)->where('external_event_id',$v['id'])->exists())return response()->json(['status'=>'duplicate']);$event=LockWebhookEvent::create(['provider_key'=>$providerKey,'external_event_id'=>$v['id']??null,'event_type'=>$v['type'],'payload'=>$request->all()]);try{$device=LockDevice::where('provider',$providerKey)->where('external_id',$v['device_id'])->firstOrFail();$updates=['last_event_at'=>now(),'last_seen_at'=>now()];if(isset($v['status']))$updates['status']=$v['status'];if(isset($v['battery_level']))$updates['battery_level']=$v['battery_level'];if(in_array($v['type'],['offline','tamper']))$updates['status']=$v['type']==='offline'?'offline':$device->status;$device->update($updates);if($device->room_id)RoomEvent::create(['room_id'=>$device->room_id,'event_type'=>'lock_'.$v['type'],'description'=>'Lock event: '.str_replace('_',' ',$v['type']).'.','metadata'=>$request->all(),'occurred_at'=>$v['occurred_at']??now()]);AuditLogger::actor(null,'lock_webhook_'.$v['type'],'access',in_array($v['type'],['tamper','forced_entry'])?'critical':(in_array($v['type'],['offline','low_battery'])?'warning':'normal'),'Lock webhook received for '.$device->name.'.',$device,null,$request->all());if(in_array($v['type'],['offline','tamper','forced_entry','low_battery'])||($device->battery_level<25))Notification::send(User::whereIn('role',['super_admin','manager'])->where('status','active')->get(),new LockHealthAlert($device,"{$device->name}: ".str_replace('_',' ',$v['type'])));$event->update(['status'=>'processed','processed_at'=>now()]);return response()->json(['status'=>'processed']);}catch(\Throwable$e){$event->update(['status'=>'failed','error'=>$e->getMessage()]);throw$e;}}}
